O(n^3) solution for Optimal BST
```
def minCost(freq):
    dp = {}
    sum_freq = []
    for _ in freq:
        sum_freq.append([0 for _ in freq])
    for i in range(len(freq)):
        sum_freq[i][i] = freq[i]
        for j in range(i + 1, len(freq)):
            sum_freq[i][j] = sum_freq[i][j - 1] +  freq[j]
    return helper(freq, 0, len(freq) - 1, 1, sum_freq, dp)


def helper(freq, i, j, level, sum_freq, dp):
    if i > j:
        return 0

    s = str(i) + "#" + str(j)
    if s in dp:
        return dp[s][0] + sum_freq[i][j] * (level - dp[s][1])
    ans = float("inf")
    for ii in range(i, j + 1):
        ans = min(ans, helper(freq, i , ii - 1, level + 1, sum_freq, dp) + freq[ii] * level + 
                       helper(freq, ii + 1, j, level + 1, sum_freq, dp))
    dp[s] = [ans, level]
    return ans
